import React, { useState } from "react";
import "./Login.css";
import bg from "../assetss/1stbg.jpg.jpeg"; // background image

function Login({ toggleSignup, goForgot,goHome }) {
  const [formData, setFormData] = useState({
    email: '',
    password: ''
  });

  const [message, setMessage] = useState('');

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setMessage('Logging in...');

    try {
      console.log('Attempting login with:', { email: formData.email, password: '[HIDDEN]' });
      const response = await fetch('http://localhost:5002/api/login', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(formData),
      });

      console.log('Response status:', response.status);
      const data = await response.json();
      console.log('Response data:', data);

      if (response.ok) {
        setMessage('Login successful!');
        setTimeout(() => goHome(), 500); // redirect to HomePage
      } else {
        setMessage(`Login failed: ${data.message}`);
      }

    } catch (error) {
      console.error('Login error:', error);
      setMessage(`Network error: ${error.message}`);
    }
  };

  return (
    <div
      className="login-container"
      style={{ backgroundImage: `url(${bg})` }}
    >
      <div className="login-box">

        {/* Header */}
        <div className="login-header">
          <h1>LOGIN</h1>
        </div>

        {/* Login form */}
        <form className="login-form" onSubmit={handleSubmit}>

          <input
            type="email"
            name="email"
            placeholder="Email"
            value={formData.email}
            onChange={handleChange}
            required
          />

          <input
            type="password"
            name="password"
            placeholder="Password"
            value={formData.password}
            onChange={handleChange}
            required
          />

          {/* Forgot Password */}
          <p
            className="forgot"
            style={{ cursor: "pointer" }}
            onClick={goForgot}
          >
            Forgot password?
          </p>

          <button type="submit">Login</button>

          {message && (
            <p style={{ color: "white", marginTop: "10px" }}>
              {message}
            </p>
          )}

          {/* Signup link */}
          <p className="signup">
            Don't have an account?{" "}
            <span
              style={{ cursor: "pointer", color: "yellow" }}
              onClick={toggleSignup}
            >
              Sign up
            </span>
          </p>

        </form>

      </div>
    </div>
  );
}

export default Login;
